def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity == 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 2:
            priorities[i] = ratio ** 3 + np.log(ratio) * 2
        elif 1 < ratio <= 2:
            priorities[i] = (1 / (2 - ratio + 1e-9)) ** 2 + np.sin(ratio * np.pi)
        elif 0.7 < ratio <= 1:
            priorities[i] = 1 / (1 - ratio + 1e-9) + np.exp(-ratio)
        else:
            sum_log = 0
            count = 0
            for j in range(1, 7):
                val = ratio + j * 0.08
                if val < 1:
                    sum_log += np.log(1 - val + 1e-9)
                    count += 1
            avg_log = -sum_log / (count if count > 0 else 1)
            penalty = 0
            for k in range(1, 4):
                if ratio < 0.3 * k:
                    penalty += (0.3 * k - ratio) ** 2
            priorities[i] = avg_log + penalty
        if capacity < item * 0.5:
            priorities[i] *= 1.5
        elif capacity > item * 2:
            priorities[i] *= 0.7
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size > 0:
        max_priority = np.max(finite_priorities)
        for i in range(len(priorities)):
            if np.isinf(priorities[i]):
                priorities[i] = max_priority * 3
    else:
        priorities.fill(0)
    return priorities
